import { AgentRuntime, TelemetryEvent } from '@azure/ai-projects';

const PII_REGEX = [
  /\b\d{3}-\d{2}-\d{4}\b/g,  // SSN
  /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g,  // Email
  /\b\d{3}-\d{3}-\d{4}\b/g   // Phone
];

function scanForPII(content: string): string[] {
  const findings: string[] = [];
  PII_REGEX.forEach(regex => {
    const matches = content.match(regex);
    if (matches) {
      findings.push(...matches);
    }
  });
  return findings;
}

const runtime = new AgentRuntime({
  agentId: 'your-agent-id',
  telemetry: {
    onEvent: (event: TelemetryEvent) => {
      if (event.type === 'agent_response') {
        const pii = scanForPII(event.payload.content);
        if (pii.length > 0) {
          console.error('🚨 PII detected:', pii);
          event.block = true;
        }
      }
    }
  }
});

