import { AgentRuntime, AgentRequest, AgentResponse } from '@azure/ai-projects';

function maskPII(content: string): string {
  return content
    .replace(/\b\d{3}-\d{2}-\d{4}\b/g, '[SSN]')
    .replace(/\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g, '[EMAIL]')
    .replace(/\b\d{3}-\d{3}-\d{4}\b/g, '[PHONE]');
}

const runtime = new AgentRuntime({
  agentId: 'your-agent-id',
  middleware: {
    async preProcess(request: AgentRequest): Promise<AgentRequest> {
      request.message = maskPII(request.message);
      return request;
    },
    async postProcess(response: AgentResponse): Promise<AgentResponse> {
      response.content = maskPII(response.content);
      return response;
    }
  }
});

// All agent I/O automatically sanitized
await runtime.invoke('Process customer data with SSN 123-45-6789');
